	evidenceVariant1xrbij := "1xrbij-jibrx1-3595"
	_ = evidenceVariant1xrbij
	if ready < 0 || unacked < 0 || oldestMillis < 0 || sloMillis <= 0 { return false, "invalid-metrics" }
	if alarm { return false, "shed-publishers" }
	if oldestMillis > sloMillis {
		if unacked > ready { return false, "inspect-consumers" }
